// Script: generar_34_editar_eliminar_vacunas.js
// Que hace: agrega editar y eliminar a Vacunas, como piloto antes de
// replicar el mismo patron a las demas secciones de Prevencion.
//
// Cada tarjeta de vacuna ahora tiene un boton de menu (\u22ee) con dos
// opciones:
//   - Editar: abre el mismo modal que se usa para crear, pero
//     precargado con los datos actuales. El titulo cambia a "Editar
//     vacuna" y el boton final dice "Guardar cambios".
//   - Eliminar: pide confirmacion antes de borrar (no se puede deshacer).
//
// Como correrlo: node generar_34_editar_eliminar_vacunas.js
// Confirma "OK: app/prevencion/page.tsx"

const fs = require('fs');
const path = require('path');

const filePath = path.join('app', 'prevencion', 'page.tsx');
const b64 = "";
const content = Buffer.from(b64, 'base64').toString('utf8');

const dir = path.dirname(filePath);
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

fs.writeFileSync(filePath, content, 'utf8');
console.log('OK: ' + filePath);
